/**
 * Returns an array of FAQ objects {q, a} for the given blog.
 * Tries categorySlug first, then slug aliases, then falls back to default.
 */
export function getBlogFAQs(blog) {
  const cat = blog.categorySlug || '';
  const faqs =
    FAQ_MAP[cat] ||
    FAQ_MAP[SLUG_ALIASES[cat]] ||
    FAQ_MAP.default;
  return faqs.slice(0, 13); // return up to 13
}
